"use server";

import { revalidateTag } from "next/cache";

export async function createTechnologyAction(formData: FormData) {
    const technologyName = formData.get('technologyName') as string;
    const technologyImage = formData.get('technologyImageName') as string;
    const technologyImageLink = formData.get('technologyImageLink') as string;

    if (!technologyName || !technologyImage || !technologyImageLink) {
        throw new Error('Todos os campos são obrigatórios');
    }
    const response = await fetch(`${process.env.API_URL}/technologies`, {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json'
        },
        body: JSON.stringify({
            name: technologyName,
            image: {
                name: technologyImage,
                imageLink: technologyImageLink
            }
        })
    });

    if (!response.ok) {
        throw new Error('Erro ao criar tecnologia');
    }

    revalidateTag("technologies")
}

export async function deleteItem(endpoint: string, identifier: string, tagToRevalidate: string) {
    try {
        const response = await fetch(`${process.env.API_URL}/${endpoint}/${identifier}`, {
            method: "DELETE",
            headers: {
                "Content-Type": "application/json",
            },
        });

        const data = await response.json();
        revalidateTag(tagToRevalidate)

        return data
    } catch (error: unknown) {
        console.error(error)
    }
}

export async function createExperience(formData: FormData) {

    const title = formData.get("title") as string

    const description = formData.get("description") as string

    const startedAt = new Date(formData.get("startedAt") as string)

    const finishedAt = new Date(formData.get("finishedAt") as string)

    const response = await fetch(`${process.env.API_URL}/experiences`, {
        method: "POST",
        headers: {
            "Content-Type": "application/json",
        },
        body: JSON.stringify({
            title,
            description,
            startedAt,
            finishedAt
        })
    })

    revalidateTag("experiences");
}

export async function createProjectAction(formData: FormData) {
    'use server';
    const projectName = formData.get('projectName') as string;
    const slug = formData.get('slug') as string;
    const description = formData.get('description') as string;
    const projectLink = formData.get('projectLink') as string;
    const githubLink = formData.get('githubLink') as string;
    const projectImageName = formData.get('projectImageName') as string;
    const imageLink = formData.get('imageLink') as string;
    const technologies = formData.get('technologies') as string;
    const techArray = technologies
      .split(',')
      .map((tech) => tech.trim())
      .filter((tech) => tech !== '');

    const response = await fetch(`${process.env.API_URL}/projects`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        projectName,
        slug,
        description,
        projectLink,
        githubLink,
        image: {
          name: projectImageName,
          imageLink
        },
        technologyIds: techArray
      })
    });
  }